args.cypher:
// Check if there are any other AAS shells whose assets are somehow associated with Hall 4
// besides those in the hierarchical structures
MATCH (aas:AssetAdministrationShell)-[:HAS_SUBMODEL]->(sm:Submodel)
MATCH (sm)-[:HAS_ELEMENT*]->(el:Property)
WHERE el.idShort = 'Location' OR el.idShort = 'Hall'
RETURN DISTINCT aas.idShort, el.idShort, el.value

// List all distinct semantic IDs in the graph
MATCH (sm:Submodel)-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept)
RETURN DISTINCT sc.id

// Get all elements from the FacilityInformation submodel of Hall 4
MATCH (sm:Submodel {id: 'urn:submodel:hall4:facilityinformation'})-[:HAS_ELEMENT*]->(el:SubmodelElement)
RETURN el.idShort, labels(el) AS types, el.value, el.smId

// Traverse the HierarchicalStructures submodel of Hall4 to find all entities
MATCH (sm:Submodel {id: $smId})-[:HAS_ELEMENT*]->(e:Entity)
RETURN e.idShort, e.entityType, e.smId

// Get FacilityInformation for Hall 4
MATCH (sm:Submodel {id: $smId})-[:HAS_ELEMENT*]->(p:Property)
RETURN p.idShort AS property, p.value AS value

// Check exact semanticId for HierarchicalStructures submodels - list all semanticIds
MATCH (sm:Submodel)-[:HAS_SEMANTIC_ID]->(sc:SemanticConcept)
RETURN DISTINCT sc.id

// Find all AAS shells
MATCH (aas:AssetAdministrationShell)-[:MANAGES_ASSET]->(a:Asset)
RETURN aas.idShort, aas.id, a.globalAssetId, a.assetType
